#!/usr/bin/env python3\n\"\"\"\nReward function for Generation 49: Simplified sparse terminal bonus.\nDeath penalty -20000, small per-step success bonus.\nTerminal bonus +10000 if episode distribution within target range (15-35% each).\n\"\"\"\ndef compute_reward_gen49(self, tool_name, tool_args, tool_result):\n    # If error, penalize\n    if isinstance(tool_result, dict) and \"error\" in tool_result:\n        return -10.0\n    \n    # Declare death penalty (extremely heavy)\n    if tool_name == \"declare_death\":\n        return -20000.0\n    \n    # Issue tools penalty\n    issue_tools = [\"list_issues\", \"read_issue\", \"comment_issue\", \"close_issue\", \"create_issue\"]\n    if tool_name in issue_tools:\n        return -100.0\n    \n    # Write note penalty\n    if tool_name == \"write_note\":\n        return -50.0\n    \n    # List files penalty\n    if tool_name == \"list_files\":\n        return -50.0\n    \n    productive_tools = [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]\n    \n    reward = 0.0\n    # Success reward (small)\n    if isinstance(tool_result, dict) and not tool_result.get(\"error\"):\n        reward += 5.0\n    \n    # Extra per tool (small)\n    if tool_name in productive_tools:\n        reward += 2.0\n    \n    # Track episode counts\n    if not hasattr(self, 'episode_counts'):\n        self.episode_counts = {tool: 0 for tool in productive_tools}\n        self.episode_total = 0\n    if tool_name in productive_tools:\n        self.episode_counts[tool_name] += 1\n        self.episode_total += 1\n    \n    # Slight penalty for using same tool as last step\n    if hasattr(self, 'last_tool') and tool_name == self.last_tool:\n        reward -= 0.5\n    self.last_tool = tool_name\n    \n    # Clip reward to reasonable range\n    if reward > 100.0:\n        reward = 100.0\n    elif reward < -100.0:\n        reward = -100.0\n    return reward\n\ndef compute_terminal_bonus_gen49(self):\n    \"\"\"\n    Compute terminal bonus at episode end based on distribution.\n    Returns bonus (positive) if distribution within target range.\n    \"\"\"\n    productive_tools = [\"write_file\", \"execute_code\", \"modify_self\", \"read_file\"]\n    if not hasattr(self, 'episode_counts'):\n        return 0.0\n    total = self.episode_total\n    if total < 5:\n        return 0.0\n    within_target = True\n    for tool in productive_tools:\n        prop = self.episode_counts[tool] / total\n        if not (0.15 <= prop <= 0.35):\n            within_target = False\n            break\n    if within_target:\n        return 10000.0\n    else:\n        return 0.0